import sys
from collections import defaultdict

def read_ints():
    return map(int, sys.stdin.readline().split())

def main():
    N, S = read_ints()
    size = [0] * (N + 1)
    power = [0] * (N + 1)
    for i in range(1, N + 1):
        s, p = read_ints()
        size[i] = s
        power[i] = p

    graph = defaultdict(list)
    for _ in range(N - 1):
        u, v = read_ints()
        graph[u].append(v)
        graph[v].append(u)

    parent = [-1] * (N + 1)
    dfs_order = []
    stack = [1]
    while stack:
        node = stack.pop()
        dfs_order.append(node)
        for neighbor in graph[node]:
            if neighbor != parent[node]:
                parent[neighbor] = node
                stack.append(neighbor)

    dp = [[0] * (S + 1) for _ in range(N + 1)]
    for node in reversed(dfs_order):
        for neighbor in graph[node]:
            if neighbor == parent[node]:
                continue
            for j in range(S + 1):
                dp[node][j] = max(dp[node][j], dp[node][j - size[node]] + power[node] if j >= size[node] else 0)
                if j >= size[neighbor]:
                    dp[node][j] = max(dp[node][j], dp[node][j - size[neighbor]] + dp[neighbor][size[neighbor]])
        for j in range(S + 1):
            if j >= size[node]:
                dp[node][j] = max(dp[node][j], dp[node][S - size[node]] + power[node])

    print(max(dp[1]))

if __name__ == "__main__":
    main()
