import math

def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def count_divisions(n, p):
    count = 0
    while n % p == 0:
        n //= p
        count += 1
    return count

def prime_factors(n):
    factors = {}
    if n % 2 == 0:
        factors[2] = count_divisions(n, 2)
        while n % 2 == 0:
            n //= 2
    i = 3
    while i * i <= n:
        if n % i == 0:
            factors[i] = count_divisions(n, i)
            while n % i == 0:
                n //= i
        i += 2
    if n > 1:
        factors[n] = 1
    return factors

def main():
    try:
        A, B = map(int, input().split())
        product_factors = {}
        for p, count in {**prime_factors(A), **prime_factors(B)}.items():
            product_factors[p] = product_factors.get(p, 0) + count
        if A == B or not is_prime(A) or not is_prime(B):
            if any(count >= 2 for count in product_factors.values()):
                print('no credit')
            else:
                print('partial credit')
        else:
            print('full credit')
    except Exception as e:
        # In a real competition, you might want to log this error
