import sys

def calculate_prefix_sum(dna):
    prefix_sum = [[0, 0, 0, 0] for _ in range(len(dna) + 1)]
    for i in range(len(dna)):
        prefix_sum[i + 1] = prefix_sum[i].copy()
        if dna[i] == 'A':
            prefix_sum[i + 1][0] += 1
        elif dna[i] == 'T':
            prefix_sum[i + 1][1] += 1
        elif dna[i] == 'G':
            prefix_sum[i + 1][2] += 1
        else:
            prefix_sum[i + 1][3] += 1
    return prefix_sum

def get_nucleotide_counts(prefix_sum, start, end):
    counts = [0, 0, 0, 0]
    for i in range(4):
        counts[i] = prefix_sum[end][i] - prefix_sum[start - 1][i]
    return counts

def get_sorted_nucleotides(counts):
    nucleotides = ['A', 'T', 'G', 'C']
    sorted_nucleotides = sorted(range(4), key=lambda x: (-counts[x], x))
    return ''.join([nucleotides[i] for i in sorted_nucleotides])

def main():
    dna = sys.stdin.readline().strip()
    prefix_sum = calculate_prefix_sum(dna)
    num_queries = int(sys.stdin.readline().strip())
    for _ in range(num_queries):
        start, end = map(int, sys.stdin.readline().strip().split())
        counts = get_nucleotide_counts(prefix_sum, start, end)
        print(get_sorted_nucleotides(counts))

