import sys
import heapq

def read_ints():
    return map(int, sys.stdin.readline().split())

def main():
    n, m, a, b = read_ints()
    a -= 1
    b -= 1

    graph = [[] for _ in range(n)]
    total_length = 0

    for _ in range(m):
        i1, i2, length = read_ints()
        i1 -= 1
        i2 -= 1
        graph[i1].append((i2, length))
        graph[i2].append((i1, length))
        total_length += length

    distances = [float('inf')] * n
    distances[a] = 0

    pq = [(0, a)]
    while pq:
        dist, node = heapq.heappop(pq)
        if dist > distances[node]:
            continue
        for neighbor, length in graph[node]:
            new_dist = dist + length
            if new_dist < distances[neighbor]:
                distances[neighbor] = new_dist
                heapq.heappush(pq, (new_dist, neighbor))

    shortest_paths_count = [0] * n
    shortest_paths_count[a] = 1

    pq = [(distances[a], a)]
    while pq:
        dist, node = heapq.heappop(pq)
        if dist > distances[node]:
            continue
        for neighbor, length in graph[node]:
            if distances[neighbor] == dist - length:
                shortest_paths_count[neighbor] += shortest_paths_count[node]
                heapq.heappush(pq, (distances[neighbor], neighbor))

    used_length = 0
    for i in range(n):
        for j, length in graph[i]:
            if distances[i] + length == distances[j]:
                used_length += length * (shortest_paths_count[i] / shortest_paths_count[j])

    print(total_length - used_length // 2)

if __name__ == "__main__":
    main()
