def main():
    n = int(input())
    tasks = [int(input()) for _ in range(n)]

    # dp[i][mask] represents the maximum number of tasks completed
    # after i tasks with the tools represented by 'mask' available.
    # mask is a bitmask where bit 0 represents hammer (for nails),
    # bit 1 represents screwdriver (for screws), and bit 2 represents wrench (for bolts).
    dp = {-1: -1 for _ in range(8)}
    dp[7] = 0  # Initially, all tools are available.

    for task in tasks:
        new_dp = dp.copy()
        for mask in dp:
            if dp[mask] == -1:
                continue
            # Try to complete the task if the corresponding tool is available.
            if (mask & (1 << task)) != 0:
                new_dp[mask] = max(new_dp[mask], dp[mask] + 1)
            # Try to drop a tool to complete the task if the corresponding tool is not available.
            else:
                for tool in range(3):
                    if (mask & (1 << tool)) != 0:
                        new_mask = mask ^ (1 << tool)
                        if (new_mask & (1 << task)) != 0:
                            new_dp[new_mask] = max(new_dp[new_mask], dp[mask] + 1)
        dp = new_dp

    print(max(dp.values()))

