import sys

def read_input():
    m, n, k, s = map(int, sys.stdin.readline().strip().split())
    x1 = sorted(list(map(float, sys.stdin.readline().strip().split())))
    x2 = sorted(list(map(float, sys.stdin.readline().strip().split())))
    return m, n, k, s, x1, x2

def cost(x, points):
    total_cost = 0
    for p in points:
        left, right = 0, len(x) - 1
        while right - left > 1:
            mid = (left + right) // 2
            if x[mid] <= p:
                left = mid
            else:
                right = mid
        if left == len(x) - 1:
            total_cost += (x[left] - p) ** 2
        elif right == 0:
            total_cost += (x[right] - p) ** 2
        else:
            d1 = x[left] - p
            d2 = x[right] - p
            if d1 ** 2 < d2 ** 2:
                total_cost += d1 ** 2
            else:
                total_cost += d2 ** 2
    return total_cost

def main():
    m, n, k, s, x1, x2 = read_input()
    combined = sorted([(x, 1) for x in x1] + [(x, 2) for x in x2])
    points = []
    current = []
    for x, road in combined:
        if road == 1:
            current.append((x, s ** 2 / 4))
        else:
            if current:
                points.append((sum(v for _, v in current) + s ** 2 / 4) / len(current))
                current = []
            points.append(x)
    if current:
        points.append(sum(v for _, v in current) / len(current))

    def f(i, j):
        if j == 0:
            return cost(points[i:], x1) + cost(points[i:], x2)
        return cost(points[i:j], x1) + cost(points[i:j], x2)

    dp = [[float('inf')] * (k + 1) for _ in range(len(points) + 1)]
    dp[0][0] = 0
    for i in range(len(points)):
        for j in range(k + 1):
            if dp[i][j] != float('inf'):
                for l in range(j + 1, k + 1):
                    if i + l - j <= len(points):
                        dp[i + l - j][l] = min(dp[i + l - j][l], dp[i][j] + f(i, i + l - j))
    print(f'{dp[-1][-1]:.10f}')

if __name__ == '__main__':
    main()
