        elif closest_idx == len(x) - 1:
            pass
        else:
            if abs(x[closest_idx] - point) > abs(x[closest_idx + 1] - point):
                closest_idx += 1
        total_cost += (x[closest_idx] - point) ** 2
    return total_cost

