import sys

def read_input():
    m, n, k, s = map(int, sys.stdin.readline().strip().split())
    x1 = sorted(list(map(float, sys.stdin.readline().strip().split())))
    x2 = sorted(list(map(float, sys.stdin.readline().strip().split())))
    return m, n, k, s, x1, x2

def cost(x, s, access_points):
    total_cost = 0
    for xi in x:
        min_dist = float('inf')
        for ap in access_points:
            dist = (xi - ap) ** 2
            if dist < min_dist:
                min_dist = dist
        total_cost += min_dist
    return total_cost

def find_access_points(x, k):
    n = len(x)
    prefix_sum = [0] * (n + 1)
    prefix_sum_sq = [0] * (n + 1)
    for i in range(n):
        prefix_sum[i + 1] = prefix_sum[i] + x[i]
        prefix_sum_sq[i + 1] = prefix_sum_sq[i] + x[i] ** 2

    def get_cost(left, right):
        sum_x = prefix_sum[right + 1] - prefix_sum[left]
        sum_x_sq = prefix_sum_sq[right + 1] - prefix_sum_sq[left]
        count = right - left + 1
        mean = sum_x / count
        return sum_x_sq - 2 * mean * sum_x + count * mean ** 2

    dp = [[float('inf')] * (k + 1) for _ in range(n + 1)]
    dp[0][0] = 0
    for i in range(1, n + 1):
        dp[i][1] = get_cost(0, i - 1)
    for j in range(2, k + 1):
        for i in range(j, n + 1):
            for left in range(j - 1, i):
                dp[i][j] = min(dp[i][j], dp[left][j - 1] + get_cost(left, i - 1))
    return dp[n][k]

def main():
    m, n, k, s, x1, x2 = read_input()
    access_points1 = []
    access_points2 = []
    for i in range(k):
        if i % 2 == 0:
            access_points1.append(x1[len(x1) * i // k])
            access_points2.append(x2[len(x2) * i // k])
        else:
            access_points1.append((x1[len(x1) * i // k] + x2[len(x2) * i // k]) / 2)
            access_points2.append((x1[len(x1) * i // k] + x2[len(x2) * i // k]) / 2)

    min_cost = float('inf')
    for ap1, ap2 in [(access_points1, access_points2), (access_points2, access_points1)]:
        for offset in [0, s / 2, s]:
            access_points = [ap + offset for ap in ap1]
            total_cost = cost(x1, 0, access_points) + cost(x2, s, access_points)
            min_cost = min(min_cost, total_cost)

            access_points = [ap + offset for ap in ap2]
            total_cost = cost(x2, 0, access_points) + cost(x1, s, access_points)
            min_cost = min(min_cost, total_cost)

    print(min_cost)

if __name__ == "__main__":
