import sys

def read_input():
    m, n, k, s = map(int, sys.stdin.readline().strip().split())
    x1 = sorted(list(map(float, sys.stdin.readline().strip().split())))
    x2 = sorted(list(map(float, sys.stdin.readline().strip().split())))
    return m, n, k, s, x1, x2

def cost(x, points):
    total_cost = 0
    for xi in x:
        min_dist = float('inf')
        for point in points:
            dist = (xi - point) ** 2
            if dist < min_dist:
                min_dist = dist
        total_cost += min_dist
    return total_cost

def kmeans(x, k):
    if not x:
        return []
    points = sorted(x)[::max(1, len(x)//k)]
    if len(points) < k:
        points += [x[-1]] * (k - len(points))
    while True:
        clusters = [[] for _ in range(k)]
        for xi in x:
            min_dist = float('inf')
            closest_point_index = -1
            for i, point in enumerate(points):
                dist = (xi - point) ** 2
                if dist < min_dist:
                    min_dist = dist
                    closest_point_index = i
            clusters[closest_point_index].append(xi)
        new_points = [sum(cluster) / len(cluster) if cluster else points[i] for i, cluster in enumerate(clusters)]
        if new_points == points:
            break
        points = new_points
    return points

def main():
    m, n, k, s, x1, x2 = read_input()
    points = kmeans(x1 + [x + 0.0 for x in x2], k)
    total_cost = cost(x1, points) + cost(x2, points) + (m + n) * (s ** 2) / 4
    print(total_cost)

if __name__ == "__main__":
    main()
