import sys

def kmp_table(s):
    n = len(s)
    table = [0] * (n + 1)
    table[0] = -1
    i, j = 0, -1
    while i < n:
        while j >= 0 and s[i] != s[j]:
            j = table[j]
        i += 1
        j += 1
        table[i] = j
    return table

def build_dfa(s, alphabet):
    dfa = [[0] * len(alphabet) for _ in range(len(s))]
    table = kmp_table(s)
    for i in range(len(s)):
        for j, c in enumerate(alphabet):
            k = i
            while k >= 0 and s[k] != c:
                k = table[k]
            dfa[i][j] = k + 1 if k < len(s) else k
    return dfa

def impartial(a, s, t):
    alphabet = list(a)
    alphabet_map = {c: i for i, c in enumerate(alphabet)}
    s_dfa = build_dfa(s, alphabet)
    t_dfa = build_dfa(t, alphabet)
    s_state = 0
    t_state = 0
    seen = set()
    stack = [(s_state, t_state)]
    while stack:
        s_state, t_state = stack.pop()
        if (s_state, t_state) in seen:
            continue
        seen.add((s_state, t_state))
        if s_state == len(s) or t_state == len(t):
            if s_state == len(s) and t_state == len(t):
                return False
            else:
                continue
        for c in alphabet:
            next_s_state = s_dfa[s_state][alphabet_map[c]]
            next_t_state = t_dfa[t_state][alphabet_map[c]]
            stack.append((next_s_state, next_t_state))
    return True

def main():
    input = sys.stdin.readline
    k = int(input().strip())
    for _ in range(k):
        a, s, t = input().strip().split()
        print(1 if impartial(a, s, t) else 0)

if __name__ == "__main__":
    main()
