def build_dfa(s, alphabet):
    dfa = [[0] * len(alphabet) for _ in range(len(s))]
    table = kmp_table(s)
    for state in range(len(s)):
        for char in range(len(alphabet)):
            if state < len(s) and alphabet[char] == s[state]:
                dfa[state][char] = state + 1
            else:
                j = state
                while j >= 0 and (alphabet[char] != s[j]):
                    j = table[j]
                dfa[state][char] = j + 1
    return dfa

def impartial_strings(alphabet, s, t):
    dfa_s = build_dfa(s, alphabet)
    dfa_t = build_dfa(t, alphabet)
    n, m = len(s), len(t)
    pairs = [(0, 0)]
    visited = {(0, 0)}
