                next_state_t = dfa_t[state_t][char]
                if next_state_s != n and next_state_t != m and (next_state_s, next_state_t) not in visited:
                    visited.add((next_state_s, next_state_t))
                    new_pairs.append((next_state_s, next_state_t))
